import { describe, expect, it } from 'vitest';

import {
  admitSpeed,
  DopplerSpeedMaster,
  dopplerSpeedRusticCertificate,
  erratic,
  monotoneNonIncreasing,
  moving,
  stationary,
  totalDrop,
  type Sweep,
} from '../src/doppler-speed';

const opts = { minDrop: 10 } as const;

describe('monotoneNonIncreasing (mirrors monotoneNonIncreasingB)', () => {
  it('a clean descending pass is monotone non-increasing', () => {
    expect(monotoneNonIncreasing(moving)).toBe(true);
  });

  it('a flat sweep is (vacuously) monotone non-increasing', () => {
    expect(monotoneNonIncreasing(stationary)).toBe(true);
  });

  it('an erratic rise-and-fall is NOT monotone', () => {
    expect(monotoneNonIncreasing(erratic)).toBe(false);
  });

  it('empty and singleton sweeps are vacuously monotone', () => {
    expect(monotoneNonIncreasing([])).toBe(true);
    expect(monotoneNonIncreasing([42])).toBe(true);
  });

  it('a single rise anywhere breaks monotonicity', () => {
    expect(monotoneNonIncreasing([100, 90, 95, 80])).toBe(false);
    expect(monotoneNonIncreasing([100, 90, 80, 70])).toBe(true);
  });
});

describe('totalDrop (the speed proxy, mirrors totalDrop / flat_has_zero_drop)', () => {
  it('is head minus last for a descending pass', () => {
    expect(totalDrop(moving)).toBe(50);
  });

  it('a flat sweep drops to zero', () => {
    expect(totalDrop(stationary)).toBe(0);
    expect(totalDrop([100, 100, 100])).toBe(0);
  });

  it('saturates at zero when the last exceeds the head', () => {
    // erratic head 100, last 130 -> saturating 100 - 130 = 0
    expect(totalDrop(erratic)).toBe(0);
  });

  it('is zero on the empty sweep', () => {
    expect(totalDrop([])).toBe(0);
  });

  it('a singleton sweep has zero drop (head == last)', () => {
    expect(totalDrop([77])).toBe(0);
  });
});

describe('promotion check: admitSpeed', () => {
  it('admits a monotone sweep whose drop clears the floor', () => {
    // mirrors moving_admitted
    const a = admitSpeed(moving, opts);
    expect(a.outcome).toBe('claim_admitted');
    expect(a.limitation).toBe('none');
    expect(a.monotone).toBe(true);
    expect(a.totalDrop).toBe(50);
  });

  it('withholds an erratic (non-monotone) sweep (no clean pass)', () => {
    // mirrors erratic_rejected
    const a = admitSpeed(erratic, opts);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('not_one_clean_pass');
    expect(a.monotone).toBe(false);
  });

  it('withholds a monotone but low-drop (stationary) sweep', () => {
    // mirrors stationary_rejected / flat_not_admitted
    const a = admitSpeed(stationary, opts);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('insufficient_drop');
    expect(a.monotone).toBe(true);
    expect(a.totalDrop).toBe(0);
  });

  it('the monotone gate takes priority over the drop gate', () => {
    // an erratic sweep is withheld on the monotone gate even if head-last is big
    const a = admitSpeed([200, 250, 10], opts);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('not_one_clean_pass');
  });

  it('a monotone sweep exactly at the drop floor is admitted', () => {
    // drop exactly 10 clears minDrop 10 (>= floor)
    const exact: Sweep = [110, 105, 100];
    expect(totalDrop(exact)).toBe(10);
    const a = admitSpeed(exact, opts);
    expect(a.outcome).toBe('claim_admitted');
  });

  it('a monotone sweep just below the floor is withheld', () => {
    const below: Sweep = [109, 105, 100];
    expect(totalDrop(below)).toBe(9);
    const a = admitSpeed(below, opts);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('insufficient_drop');
  });
});

describe('DopplerSpeedMaster (mirrors doppler_master)', () => {
  it('every boundary witness holds', () => {
    expect(DopplerSpeedMaster.movingAdmitted).toBe(true);
    expect(DopplerSpeedMaster.stationaryRejected).toBe(true);
    expect(DopplerSpeedMaster.erraticRejected).toBe(true);
    expect(DopplerSpeedMaster.movingMonotone).toBe(true);
    expect(DopplerSpeedMaster.erraticNotMonotone).toBe(true);
    expect(DopplerSpeedMaster.movingDrop).toBe(true);
    expect(DopplerSpeedMaster.stationaryDrop).toBe(true);
    expect(DopplerSpeedMaster.flatHasZeroDrop).toBe(true);
    expect(DopplerSpeedMaster.movingVsStationary).toBe(true);
    expect(DopplerSpeedMaster.certStationaryRejected).toBe(true);
    expect(DopplerSpeedMaster.certErraticRejected).toBe(true);
  });

  it('the certificate records all gates', () => {
    expect(dopplerSpeedRusticCertificate.sweepModeled).toBe(true);
    expect(dopplerSpeedRusticCertificate.monotoneGated).toBe(true);
    expect(dopplerSpeedRusticCertificate.dropSupported).toBe(true);
    expect(dopplerSpeedRusticCertificate.stationaryRejected).toBe(true);
    expect(dopplerSpeedRusticCertificate.erraticRejected).toBe(true);
  });
});
